mapper.select:
/* mapper.login.com.erns.coching.AccessTokenDAO.selectList */

SELECT * FROM (
SELECT A.*,ROWNUM RN, COUNT(*) OVER() TOTAL FROM (
SELECT

FROM T_TOKEN_ACCESS AA



ORDER BY REG_DATE DESC
) A

	) WHERE RN BETWEEN #{offset} AND #{offset} + #{rowSize}

/* mapper.login.com.erns.coching.AccessTokenDAO.load */

SELECT

FROM T_TOKEN_ACCESS AA

	AND AA.TOKEN = #{value, jdbcType=VARCHAR}

mapper.insert:
/* com.erns.coching.login.mapper.AccessTokenDAO.insert */

INSERT INTO T_TOKEN_ACCESS (
							 TOKEN, SITE_TYPE, DEVICE_KEY
						   , MEMB_SEQ, EXP_DATE, RGT_DTTM
)
VALUES (
		   #{token	, jdbcType=VARCHAR}
	   , #{siteType, jdbcType=VARCHAR}
	   , #{deviceKey, jdbcType=VARCHAR}
	   , #{userSeq	, jdbcType=INTEGER}
	   , #{expDate	, jdbcType=TIMESTAMP}
	   , now()
	   )

mapper.delete:
/* mapper.login.com.erns.coching.AccessTokenDAO.delete */

DELETE FROM T_TOKEN_ACCESS

	AND TOKEN = #{value, jdbcType=VARCHAR}

/* mapper.login.com.erns.coching.AccessTokenDAO.deleteExpiredTokens */

DELETE FROM T_TOKEN_ACCESS

	 AND EXP_DATE < now()
